og_m_to_linear(x: f32) -> f32 {
    let x = x as f64;
    let sl = slope();
    let ic = intercept();

    let linear = if x <= CUT_ENCODED {
        (x - ic) / sl
    } else {
        (10_f64.powf((x - D) / C) - B) / A
    };

    linear.max(0.0) as f32
}
pub fn linear_to_dlog_m(x: f32) -> f32 {
    let x = x as f64;
    let cl = cut_linear();
    let sl = slope();
    let ic = intercept();

    let encoded = if x <= cl {
        sl * x + ic
    } else {
        C * (A * x + B).log10() + D
    };

    encoded.clamp(0.0, 1.0) as f32
}
